import{_ as e,o as a,c as n,ag as i}from"./chunks/framework.DWeTidJA.js";const h=JSON.parse('{"title":"Problem Statement & Scope","description":"","frontmatter":{},"headers":[],"relativePath":"problem.md","filePath":"problem.md","lastUpdated":1769427750000}'),t={name:"problem.md"};function r(l,s,o,p,c,u){return a(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="problem-statement-scope" tabindex="-1">Problem Statement &amp; Scope <a class="header-anchor" href="#problem-statement-scope" aria-label="Permalink to &quot;Problem Statement &amp; Scope&quot;">​</a></h1><h2 id="target-use-case" tabindex="-1">Target Use Case <a class="header-anchor" href="#target-use-case" aria-label="Permalink to &quot;Target Use Case&quot;">​</a></h2><p><strong>Primary</strong>: Internal API Gateway for microservices architecture<br><strong>Secondary</strong>: Development/testing proxy with observability<br><strong>Non-goal</strong>: Edge proxy for public internet traffic (use Nginx/Envoy for that)</p><h2 id="why-this-exists" tabindex="-1">Why This Exists <a class="header-anchor" href="#why-this-exists" aria-label="Permalink to &quot;Why This Exists&quot;">​</a></h2><ul><li><strong>Flexibility</strong>: Custom routing logic, request transformation, and policy enforcement that&#39;s easier to express in JavaScript than Nginx config</li><li><strong>Observability</strong>: Deep request/response inspection with structured logging and business metrics</li><li><strong>Developer Experience</strong>: Hot-reload policies, clear error messages, easy debugging</li><li><strong>Integration</strong>: Native integration with Node.js backends, shared validation logic</li></ul><h2 id="expected-throughput" tabindex="-1">Expected Throughput <a class="header-anchor" href="#expected-throughput" aria-label="Permalink to &quot;Expected Throughput&quot;">​</a></h2><ul><li><strong>Target</strong>: 1,000-5,000 req/sec per instance</li><li><strong>Acceptable</strong>: 500+ req/sec sustained</li><li><strong>Reality Check</strong>: Node.js single-threaded nature limits raw throughput vs Nginx/Envoy <ul><li>Use clustering for scale</li><li>Better suited for &quot;smart&quot; proxy work than raw speed</li></ul></li></ul><h2 id="latency-budget" tabindex="-1">Latency Budget <a class="header-anchor" href="#latency-budget" aria-label="Permalink to &quot;Latency Budget&quot;">​</a></h2><ul><li><strong>P50</strong>: &lt; 5ms overhead</li><li><strong>P95</strong>: &lt; 20ms overhead</li><li><strong>P99</strong>: &lt; 50ms overhead</li><li><strong>Timeout</strong>: 30s default (configurable per route)</li></ul><h3 id="latency-breakdown" tabindex="-1">Latency Breakdown <a class="header-anchor" href="#latency-breakdown" aria-label="Permalink to &quot;Latency Breakdown&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Total Request Time = Proxy Overhead + Upstream Time + Network Time</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>Proxy overhead includes: auth, validation, logging, transformation</li><li>Budget assumes local network (&lt;1ms to upstream)</li></ul><h2 id="trust-boundaries" tabindex="-1">Trust Boundaries <a class="header-anchor" href="#trust-boundaries" aria-label="Permalink to &quot;Trust Boundaries&quot;">​</a></h2><h3 id="network-zones" tabindex="-1">Network Zones <a class="header-anchor" href="#network-zones" aria-label="Permalink to &quot;Network Zones&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Public Internet (UNTRUSTED)                             │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                        ▲</span></span>
<span class="line"><span>                        │ TLS termination at edge</span></span>
<span class="line"><span>                        ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ DMZ / Load Balancer (SEMI-TRUSTED)                      │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                        ▲</span></span>
<span class="line"><span>                        │ mTLS or API key</span></span>
<span class="line"><span>                        ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ THIS PROXY (ENFORCEMENT POINT)                          │</span></span>
<span class="line"><span>│  - IP filtering                                         │</span></span>
<span class="line"><span>│  - Authentication                                       │</span></span>
<span class="line"><span>│  - Rate limiting                                        │</span></span>
<span class="line"><span>│  - Request validation                                   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                        ▲</span></span>
<span class="line"><span>                        │ Internal network</span></span>
<span class="line"><span>                        ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Backend Services (TRUSTED)                              │</span></span>
<span class="line"><span>│  - Assume all requests are validated                    │</span></span>
<span class="line"><span>│  - No redundant auth checks                             │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br></div></div><h3 id="trust-assumptions" tabindex="-1">Trust Assumptions <a class="header-anchor" href="#trust-assumptions" aria-label="Permalink to &quot;Trust Assumptions&quot;">​</a></h3><ol><li><strong>Clients</strong>: UNTRUSTED until authenticated</li><li><strong>Backend Services</strong>: TRUSTED (on private network)</li><li><strong>Config Files</strong>: TRUSTED (deployed via secure pipeline)</li><li><strong>Environment Variables</strong>: TRUSTED (from secure secret manager)</li></ol><h3 id="security-posture" tabindex="-1">Security Posture <a class="header-anchor" href="#security-posture" aria-label="Permalink to &quot;Security Posture&quot;">​</a></h3><ul><li><strong>Deny by default</strong>: All routes require explicit configuration</li><li><strong>Fail closed</strong>: On config error, reject traffic (don&#39;t fall back to permissive mode)</li><li><strong>Defense in depth</strong>: Even internal clients go through auth/validation</li></ul><h2 id="constraints" tabindex="-1">Constraints <a class="header-anchor" href="#constraints" aria-label="Permalink to &quot;Constraints&quot;">​</a></h2><h3 id="hard-limits" tabindex="-1">Hard Limits <a class="header-anchor" href="#hard-limits" aria-label="Permalink to &quot;Hard Limits&quot;">​</a></h3><ul><li><strong>Max request size</strong>: 10MB (configurable)</li><li><strong>Max response size</strong>: 50MB (configurable)</li><li><strong>Max concurrent connections</strong>: 10,000 (per instance)</li><li><strong>Max request duration</strong>: 30s default, 300s maximum</li></ul><h3 id="design-constraints" tabindex="-1">Design Constraints <a class="header-anchor" href="#design-constraints" aria-label="Permalink to &quot;Design Constraints&quot;">​</a></h3><ul><li><strong>No state</strong>: Proxy is stateless for horizontal scaling <ul><li>Rate limit state in Redis</li><li>Session state in JWT/external store</li></ul></li><li><strong>Config-driven</strong>: All routing/policy in config files (not hardcoded)</li><li><strong>Graceful degradation</strong>: Degrade features before failing completely <ul><li>Example: Log sampling under load</li><li>Example: Skip non-critical validations if queue is backing up</li></ul></li></ul><h3 id="technical-debt-we-accept" tabindex="-1">Technical Debt We Accept <a class="header-anchor" href="#technical-debt-we-accept" aria-label="Permalink to &quot;Technical Debt We Accept&quot;">​</a></h3><ul><li><strong>Language choice</strong>: Node.js is slower than Go/Rust for raw proxy work <ul><li><strong>Trade-off</strong>: Developer productivity, ecosystem, shared code with backends</li></ul></li><li><strong>Single-threaded</strong>: Requires clustering for multi-core utilization <ul><li><strong>Trade-off</strong>: Simpler debugging, easier to reason about</li></ul></li><li><strong>GC pauses</strong>: Potential for occasional latency spikes <ul><li><strong>Mitigation</strong>: Memory limits, connection pooling</li></ul></li></ul><h2 id="what-this-is-not" tabindex="-1">What This Is NOT <a class="header-anchor" href="#what-this-is-not" aria-label="Permalink to &quot;What This Is NOT&quot;">​</a></h2><ul><li>❌ Not a replacement for Nginx/HAProxy for raw performance</li><li>❌ Not a service mesh (use Istio/Linkerd for that)</li><li>❌ Not a CDN or edge cache</li><li>❌ Not for public-facing traffic (unless you really need the flexibility)</li></ul><h2 id="success-metrics" tabindex="-1">Success Metrics <a class="header-anchor" href="#success-metrics" aria-label="Permalink to &quot;Success Metrics&quot;">​</a></h2><ol><li><strong>Reliability</strong>: 99.9% uptime (43 min/month downtime budget)</li><li><strong>Performance</strong>: P95 &lt; 20ms overhead</li><li><strong>Operability</strong>: Mean time to debug &lt; 5 minutes (via logs/metrics)</li><li><strong>Security</strong>: Zero SSRF/injection incidents</li></ol><h2 id="when-to-replace-this" tabindex="-1">When to Replace This <a class="header-anchor" href="#when-to-replace-this" aria-label="Permalink to &quot;When to Replace This&quot;">​</a></h2><p>Consider Nginx/Envoy when:</p><ul><li>Throughput &gt; 10K req/sec per instance needed</li><li>P99 latency must be &lt; 10ms</li><li>No custom logic required (pure reverse proxy)</li><li>Team lacks Node.js expertise</li></ul><h2 id="configuration-philosophy" tabindex="-1">Configuration Philosophy <a class="header-anchor" href="#configuration-philosophy" aria-label="Permalink to &quot;Configuration Philosophy&quot;">​</a></h2><blockquote><p><strong>Config over code, constraints over features</strong></p></blockquote><p>Every feature must answer:</p><ul><li>What&#39;s the blast radius if it fails?</li><li>How do I know it&#39;s working?</li><li>How do I turn it off quickly?</li></ul>`,37)])])}const g=e(t,[["render",r]]);export{h as __pageData,g as default};
